Rule.Source:
import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;
import sailpoint.api.IdentityService;  
import sailpoint.object.Application;
import sailpoint.object.Link;  
import sailpoint.rapidapponboarding.logger.LogEnablement;
import sailpoint.tools.GeneralException;  
import sailpoint.tools.Util;

{
  Log tlog = LogFactory.getLog("rule.ToyotaAtldapidTransformation");    
  LogEnablement.isLogTraceEnabled(tlog, "TMNA-TAT-001-Entering Toyota AtldapId Transformation Rule.");
  LogEnablement.isLogTraceEnabled(tlog, "TMNA-TAT-002-with identity "+identity.getName()+" atldapid value = "+value);    

  String returnValue = link.getAttribute("ATLDAP");
  Application orgLdap = null;
  IdentityService idService = new IdentityService(context);

  try {
    //Get the Org Ldap application object from SailPoint
    orgLdap = context.getObjectByName(Application.class , "Org LDAP");
    if ( orgLdap != null ) {
      //Get the Org Ldap link object for the user from SailPoint  
      List orgLdapLinks = idService.getLinks(identity,orgLdap);
      if ( Util.nullSafeSize(orgLdapLinks)>0 ) {
        Link orgLdapLink = orgLdapLinks.get(0);
        //Validate the Org Ldap link status for the user from SailPoint
        if ( orgLdapLink != null && !orgLdapLink.isDisabled() ) { 
          //Fetching atldapuser attribute request from the Org Ldap link 
          String atldapUserValue = orgLdapLink.getAttribute("atldapUser");
          if ( Util.nullSafeCaseInsensitiveEq(atldapUserValue,"Y") ) {
            //Synchronize identity attribute AtldapId to update Workerdb Application Atldap attribute only if atldapuser value is Y
            returnValue = value;
          }else{
            returnValue = "";
          }
        }
      }
    }
  } catch (Exception ex) {
    LogEnablement.isLogTraceEnabled(tlog, "TMNA-TAT-003-ERROR for User: " +identity.getName()+ "Error Message: An exception was thrown while attempting to process Toyota AtldapId Transformation: " + ex.toString());      
  }

  LogEnablement.isLogTraceEnabled(tlog,"TMNA-TAT-004-with identity "+identity.getName()+" return value = "+value);          
  return returnValue;
}
